import { CallStatus } from "@/types/api.types";
import { Alert } from "@mui/material";

export interface IStatusMessageCase {
    status: CallStatus;
    message: string;
}

/**
 * StatusMessage component displays status alerts for API operations
 * @param correlationId - Optional correlation ID from X-Correlation-Id response header, displayed in failure cases
 */
export interface IStatusMessageProps {
    style?: React.CSSProperties;
    notStartedMessage?: string;
    successMessage?: string;
    failureMessage?: string;
    throttledMessage?: string;
    badRequestMessage?: string;
    currentStatus: CallStatus;
    correlationId?: string;
}

const rootStyle: React.CSSProperties = {
    marginTop: "1rem",
};

export const StatusMessage: React.FC<IStatusMessageProps> = (props) => {
    switch (props.currentStatus) {
        case CallStatus.NotStarted: {
            return props.notStartedMessage ? <Alert role="status" aria-live="polite" style={props.style ?? rootStyle} severity="info">{props.notStartedMessage}</Alert> : null;
        }
        case CallStatus.Success: {
            return props.successMessage ? <Alert role="status" aria-live="polite" style={props.style ?? rootStyle} severity="success">{props.successMessage}</Alert> : null;
        }
        case CallStatus.Failure: {
            const failureContent = (
                <>
                    {props.failureMessage}
                    {props.correlationId && (
                        <>
                            <br />
                            <small>Correlation ID: {props.correlationId}</small>
                        </>
                    )}
                </>
            );
            return props.failureMessage ? <Alert role="status" aria-live="polite" style={props.style ?? rootStyle} severity="error">{failureContent}</Alert> : null;
        }
        case CallStatus.Throttled: {
            const throttledContent = (
                <>
                    {props.throttledMessage || "Too many requests. Please wait a moment before trying again."}
                    {props.correlationId && (
                        <>
                            <br />
                            <small>Correlation ID: {props.correlationId}</small>
                        </>
                    )}
                </>
            );
            return <Alert role="status" aria-live="polite" style={props.style ?? rootStyle} severity="warning">{throttledContent}</Alert>;
        }
        case CallStatus.BadRequest: {
            const badRequestContent = (
                <>
                    {props.badRequestMessage || "Invalid request. Please check your input and try again."}
                    {props.correlationId && (
                        <>
                            <br />
                            <small>Correlation ID: {props.correlationId}</small>
                        </>
                    )}
                </>
            );
            return <Alert role="status" aria-live="polite" style={props.style ?? rootStyle} severity="error">{badRequestContent}</Alert>;
        }
        case CallStatus.InProgress: {
            return <Alert role="status" aria-live="polite" style={props.style ?? rootStyle} severity="info">Processing..</Alert>;
        }
        default:
            return null;
    }
};
